using System;
using System.IO;

namespace HDLG.Tests
{
    internal static class WordSetup
    {
        private static bool _initialized = false;
        private static readonly object _lock = new();

        public static void CreateWordDocs()
        {
            if (_initialized) return;
            lock (_lock)
            {
                if (_initialized) return;

                string validDocxBase64 = "";
                string emptyDocxBase64 = "";
                string invalidDocxBase64 = "aW52YWxpZCBkYXRh";

                File.WriteAllBytes("test_word.docx", Convert.FromBase64String(validDocxBase64));
                File.WriteAllBytes("test_word_empty.docx", Convert.FromBase64String(emptyDocxBase64));
                File.WriteAllBytes("test_word_invalid.docx", Convert.FromBase64String(invalidDocxBase64));

                _initialized = true;
            }
        }

        public static void Cleanup()
        {
            if (File.Exists("test_word.docx")) File.Delete("test_word.docx");
            if (File.Exists("test_word_empty.docx")) File.Delete("test_word_empty.docx");
            if (File.Exists("test_word_invalid.docx")) File.Delete("test_word_invalid.docx");
        }
    }
}
